1	const cellKey = (x: number, y: number): string => `${x},${y}`;
2	
3	const parseKey = (key: string): number[] => key.split(",").map(Number);
4	
5	const neighborKeys = (x: number, y: number): string[] => {
6	  const keys: string[] = [];
7	  for (let dx = -1; dx <= 1; dx++) {
8	    for (let dy = -1; dy <= 1; dy++) {
9	      if (dx === 0 && dy === 0) continue;
10	      keys.push(cellKey(x + dx, y + dy));
11	    }
12	  }
13	  return keys;
14	};
15	
16	export const nextGeneration = (liveCells: number[][]): number[][] => {
17	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
18	
19	  const neighborCounts = new Map<string, number>();
20	
21	  for (const [x, y] of liveCells) {
22	    for (const key of neighborKeys(x, y)) {
23	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
24	    }
25	  }
26	
27	  const nextLiveCells: number[][] = [];
28	
29	  for (const [key, count] of neighborCounts) {
30	    if (count === 3 || (count === 2 && liveSet.has(key))) {
31	      nextLiveCells.push(parseKey(key));
32	    }
33	  }
34	
35	  return nextLiveCells;
36	};
37

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells that each have only one neighbor", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
16	    const sorted = result.map(c => c.join(",")).sort();
17	    expect(sorted).toEqual(["0,0", "0,1", "1,0", "1,1"]);
18	  });
19	  it("should keep a live cell alive when it has exactly 2 live neighbors (survival)", () => {
20	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
21	    const keys = result.map(c => c.join(","));
22	    expect(keys).toContain("1,0");
23	  });
24	  it("should keep a live cell alive when it has exactly 3 live neighbors (survival)", () => {
25	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
26	    const keys = result.map(c => c.join(","));
27	    expect(keys).toContain("1,0");
28	  });
29	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
30	    // Plus/cross shape: (1,1) has 4 live neighbors -> dies
31	    const liveCells: number[][] = [[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]];
32	    const result = nextGeneration(liveCells);
33	    const keys = result.map(c => c.join(","));
34	    expect(keys).not.toContain("1,1");
35	  });
